21	class MainGame : KtxGame<KtxScreen>(), DisposableRegistry by DisposableContainer() {
22	
23	    val gameState: StateMachine<GameState, GameEvent> by lazy {
24	        inject()
25	    }
26	
27	    private fun resetPlayers() {
28	        factsOfTheWorld().setIntFact(0, Factoids.LivingPlayerCount)
29	        for (player in Players.players.values) {
30	            player.reset()
31	            factsOfTheWorld().addToInt(1, Factoids.LivingPlayerCount)
32	        }
33	    }
34	
35	    private fun stateChanged(gameState: GameState, gameEvent: GameEvent?) {
36	        debug { "$gameEvent -> $gameState" }
37	    }
38	
39	    private val gameScreen by lazy {
40	        GameScreen(gameState)
41	    }
42	
43	    override fun create() {
44	        Context.initializeContext()
45	        InjectionContext.context.register {
46	            bindSingleton(StateMachine.buildStateMachine<GameState, GameEvent>(GameState.Splash, ::stateChanged) {
47	                state(GameState.Splash) {
48	                    action { setScreen<SplashScreen>() }
49	                    edge(GameEvent.LeftSplash, GameState.Setup) {}
50	                }
51	                state(GameState.Setup) {
52	                    action { setScreen<SetupScreen>() }
53	                    edge(GameEvent.StartedGame, GameState.Running) {
54	                        action {
55	                            resetPlayers()
56	                        }
57	                    }
58	                    edge(GameEvent.StartAnimEditor, GameState.AnimEditor) {}
59	                    edge(GameEvent.StartConcept, GameState.Concept) {}
60	                    edge(GameEvent.StartMapEditor, GameState.MapEditor) {}
61	//                    edge(GameEvent.StartCharacterEditor, GameState.CharacterEditor) {}
62	                }
63	                state(GameState.Running) {
64	                    action {
65	                        setScreen<GameScreen>()
66	                        gameScreen.resume()
67	                    }
68	                    edge(GameEvent.PausedGame, GameState.Paused) {}
69	                    edge(GameEvent.GameOver, GameState.Setup) {
70	                        action {
71	                            /*
72	                            Nice stuff. So what do we do here?
73	
74	    //                         */
75	//                        FitnessTracker.fitnessData.sortBy { it.fitness }
76	//                        val lastRelevantIndex = if( FitnessTracker.fitnessData.lastIndex > 5) 5 else FitnessTracker.fitnessData.lastIndex
77	//                        val evolveThese = FitnessTracker.fitnessData.subList(0, lastRelevantIndex)
78	//                        for((index, toEvolve) in evolveThese.withIndex()) {
79	//                            toEvolve.bt.kryoThisBitchToDisk(index + 1)
80	//                        }
81	                        }
82	
83	                    }
84	                }
85	                state(GameState.Paused) {
86	                    action {
87	                        gameScreen.pause()
88	                    }
89	                    edge(GameEvent.ResumedGame, GameState.Running) {}
90	                    edge(GameEvent.ExitedGame, GameState.Setup) {}
91	                }
92	                state(GameState.AnimEditor) {
93	                    action { setScreen<AnimEditorScreen>() }
94	                    edge(GameEvent.StopAnimEditor, GameState.Setup) {}
95	                }
96	//                state(GameState.CharacterEditor) {
97	//                    action { setScreen<CharacterEditorScreen>() }
98	//                    edge(GameEvent.StopCharacterEditor, GameState.Setup) {}
99	//                }
100	                state(GameState.Concept) {
101	                    action { setScreen<ConceptScreen>() }
102	                    edge(GameEvent.StopConcept, GameState.Setup) {}
103	                }
104	                state(GameState.MapEditor) {
105	                    action { setScreen<MapEditorScreen>() }
106	                    edge(GameEvent.ExitMapEditor, GameState.Setup) {}
107	                }
108	            })
109	        }
110	        Assets.load().alsoRegister()
111	        addScreen(SplashScreen(gameState))
112	        addScreen(SetupScreen(gameState))
113	        addScreen(gameScreen)
114	        addScreen(PauseScreen(gameState))
115	        addScreen(GameOverScreen(gameState))
116	        addScreen(AnimEditorScreen(gameState))
117	        addScreen(BehaviorTreeViewScreen(gameState))
118	        addScreen(ConceptScreen(gameState))
119	        addScreen(MapEditorScreen(gameState))
120	//        addScreen(CharacterEditorScreen(gameState))
121	        gameState.initialize()
122	    }
123	}

