39	// sets the name of the .jar file this produces to the name of the game or app.
40		archiveBaseName.set(appName)
41	// the duplicatesStrategy matters starting in Gradle 7.0; this setting works.
42		duplicatesStrategy(DuplicatesStrategy.EXCLUDE)
43		dependsOn configurations.runtimeClasspath
44		from { configurations.runtimeClasspath.collect { it.isDirectory() ? it : zipTree(it) } }
45	// these "exclude" lines remove some unnecessary duplicate files in the output JAR.
46		exclude('META-INF/INDEX.LIST', 'META-INF/*.SF', 'META-INF/*.DSA', 'META-INF/*.RSA')
47		dependencies {
48			exclude('META-INF/INDEX.LIST', 'META-INF/maven/**')
49		}
50	// setting the manifest makes the JAR runnable.
51		manifest {
52			attributes 'Main-Class': application.mainClass
53		}
54	// this last step may help on some OSes that need extra instruction to make runnable JARs.
55		doLast {
56			file(archiveFile).setExecutable(true, false)
57		}
58	}
