78	fun gibs(at: Vector2, gibAngle: Float = 1000f) {
79	    for (i in Assets.enemyGibs) {
80	        val angle = if (gibAngle == 1000f) (1f..359f).random() else gibAngle
81	        val force = vec2((15f..60f).random(), 0f).setAngleDeg(angle + (-25..25).random())
82	        val gibBody = world().body {
83	            type = BodyDef.BodyType.DynamicBody
84	            position.set(at.x - 2f, at.y - 2f)
85	            linearDamping = 5f
86	            box(.3f, .1f) {
87	                friction = 10f //Tune
88	                filter {
89	                    categoryBits = Box2dCategories.gibs
90	                    maskBits = Box2dCategories.whatGibsHit
91	                }
92	            }
93	        }
94	
95	        val localPoint = vec2(-1f, 0f)
96	
97	        val gibEntity = engine().entity {
98	            with<TextureRegionComponent> {
99	                rotateWithTransform = true
100	                textureRegion = i
101	            }
102	            with<RenderableComponent> {
103	            }
104	            with<TransformComponent> {
105	                position.set(at)
106	            }
107	            with<Box2d> {
108	                body = gibBody
109	            }
110	            with<GibComponent> {
111	                coolDownRange = 1f..3f
112	                coolDown = coolDownRange.random()
113	            }
114	        }
115	        gibBody.userData = gibEntity
116	        gibBody.applyLinearImpulse(force.scl(gibBody.mass), gibBody.getWorldPoint(localPoint).cpy(), true)
117	        //gibBody.applyAngularImpulse(50f, true)
118	    }
119	}
